Using the jsonwebtoken library without proper configuration can leave your application vulnerable to JWT algorithm confusion attacks. This critical vulnerability allows attackers to forge valid tokens by exploiting how the library handles the 'alg' header.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const jwt = require('jsonwebtoken');

const app = express();
const SECRET_KEY = 'my-secret-key-2024';

// VULNERABLE: Does not specify allowed algorithms
app.get('/api/profile', (req, res) => {
  const token = req.headers.authorization?.split(' ')[1];

  if (!token) {
    return res.status(401).json({ error: 'No token provided' });
  }

  try {
    // DANGEROUS: Trusts the algorithm specified in the token header
    const decoded = jwt.verify(token, SECRET_KEY);

    res.json({
      user: decoded.username,
      role: decoded.role,
      email: decoded.email
    });
  } catch (err) {
    res.status(401).json({ error: 'Invalid token' });
  }
});

app.listen(3000);
```

**Attack Payload**:
```text
# Original token header (before base64):
{"alg": "HS256", "typ": "JWT"}

# Attacker modifies to:
{"alg": "none", "typ": "JWT"}

# Forged token (no signature required):
eyJhbGciOiJub25lIiwidHlwIjoiSldUIn0.eyJ1c2VybmFtZSI6ImFkbWluIiwicm9sZSI6ImFkbWluIiwiZW1haWwiOiJhZG1pbkBjb21wYW55LmNvbSIsImlhdCI6MTcwNDc4MDgwMH0.
```

**Why This Is Dangerous**:
- The `alg: none` attack allows tokens with no signature to be accepted as valid
- Older jsonwebtoken versions (<9.0.0) accepted `none` algorithm by default
- Attackers can forge tokens with arbitrary claims (admin roles, different user IDs)
- Algorithm switching attacks can also exploit asymmetric key confusion (RS256 to HS256)

**SECURE VERSION**:

```javascript
const express = require('express');
const jwt = require('jsonwebtoken');

const app = express();

// Use strong, randomly generated secret (store in environment)
const SECRET_KEY = process.env.JWT_SECRET;
if (!SECRET_KEY || SECRET_KEY.length < 32) {
  throw new Error('JWT_SECRET must be set and at least 32 characters');
}

// SECURE: Explicitly specify allowed algorithms
const JWT_OPTIONS = {
  algorithms: ['HS256'],  // CRITICAL: Whitelist allowed algorithms
  issuer: 'my-app',
  audience: 'my-app-users'
};

app.get('/api/profile', (req, res) => {
  const authHeader = req.headers.authorization;

  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'No token provided' });
  }

  const token = authHeader.substring(7);

  try {
    // SECURE: Algorithm is enforced, not read from token
    const decoded = jwt.verify(token, SECRET_KEY, JWT_OPTIONS);

    // Additional validation of claims
    if (!decoded.sub || !decoded.username) {
      return res.status(401).json({ error: 'Invalid token claims' });
    }

    res.json({
      user: decoded.username,
      role: decoded.role,
      email: decoded.email
    });
  } catch (err) {
    // Don't leak error details
    console.error('JWT verification failed:', err.message);
    res.status(401).json({ error: 'Invalid token' });
  }
});

app.listen(3000);
```

**Key Security Controls**:
- **Algorithm whitelisting**: `algorithms: ['HS256']` ignores the token's alg header and enforces specific algorithm
- **Issuer/Audience validation**: Prevents tokens from other applications being accepted
- **Strong secret requirements**: Enforces minimum secret length to prevent brute-force attacks
- **Secure error handling**: Logs details server-side but returns generic errors to clients

Excellent question! The RS256/HS256 confusion attack is another critical JWT vulnerability where an attacker takes a public key (meant for RS256 verification) and uses it as the HMAC secret (for HS256), creating valid signatures. Production JWT systems need proper key management, token refresh flows, and revocation capabilities.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const jwt = require('jsonwebtoken');
const crypto = require('crypto');
const Redis = require('ioredis');
const rateLimit = require('express-rate-limit');

const app = express();
app.use(express.json());

// Redis for token blacklist and refresh token storage
const redis = new Redis(process.env.REDIS_URL);

// Key configuration - use asymmetric keys in production
const JWT_CONFIG = {
  // For RS256: Use separate public/private keys
  privateKey: process.env.JWT_PRIVATE_KEY,
  publicKey: process.env.JWT_PUBLIC_KEY,

  // CRITICAL: Never allow algorithm switching
  accessTokenOptions: {
    algorithm: 'RS256',
    expiresIn: '15m',
    issuer: process.env.JWT_ISSUER || 'my-secure-app',
    audience: process.env.JWT_AUDIENCE || 'my-secure-app-users'
  },
  refreshTokenOptions: {
    algorithm: 'RS256',
    expiresIn: '7d',
    issuer: process.env.JWT_ISSUER || 'my-secure-app',
    audience: process.env.JWT_AUDIENCE || 'my-secure-app-users'
  },
  verifyOptions: {
    algorithms: ['RS256'],  // CRITICAL: Whitelist ONLY RS256
    issuer: process.env.JWT_ISSUER || 'my-secure-app',
    audience: process.env.JWT_AUDIENCE || 'my-secure-app-users',
    complete: true  // Returns decoded header for additional checks
  }
};

// Validate key configuration on startup
function validateKeyConfig() {
  if (!JWT_CONFIG.privateKey || !JWT_CONFIG.publicKey) {
    throw new Error('JWT keys must be configured');
  }

  // Ensure keys are appropriate type
  if (!JWT_CONFIG.privateKey.includes('BEGIN') || 
      !JWT_CONFIG.publicKey.includes('BEGIN PUBLIC KEY')) {
    throw new Error('Invalid key format - use PEM formatted RSA keys');
  }
}

// Generate token pair (access + refresh)
function generateTokenPair(user) {
  const jti = crypto.randomUUID();  // Unique token ID for revocation

  const accessPayload = {
    sub: user.id,
    username: user.username,
    role: user.role,
    type: 'access',
    jti: jti
  };

  const refreshPayload = {
    sub: user.id,
    type: 'refresh',
    jti: crypto.randomUUID(),
    familyId: jti  // Links refresh to access token
  };

  const accessToken = jwt.sign(
    accessPayload, 
    JWT_CONFIG.privateKey, 
    JWT_CONFIG.accessTokenOptions
  );

  const refreshToken = jwt.sign(
    refreshPayload, 
    JWT_CONFIG.privateKey, 
    JWT_CONFIG.refreshTokenOptions
  );

  return { accessToken, refreshToken, jti };
}

// Secure token verification middleware
async function verifyAccessToken(req, res, next) {
  const authHeader = req.headers.authorization;

  if (!authHeader?.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Missing authorization header' });
  }

  const token = authHeader.substring(7);

  try {
    // SECURE: Use public key for verification, enforce RS256 only
    const { payload, header } = jwt.verify(
      token, 
      JWT_CONFIG.publicKey, 
      JWT_CONFIG.verifyOptions
    );

    // Additional header validation - defense in depth
    if (header.alg !== 'RS256') {
      console.error(`Algorithm mismatch detected: ${header.alg}`);
      return res.status(401).json({ error: 'Invalid token' });
    }

    // Check token type
    if (payload.type !== 'access') {
      return res.status(401).json({ error: 'Invalid token type' });
    }

    // Check if token is blacklisted (for revocation)
    const isBlacklisted = await redis.get(`blacklist:${payload.jti}`);
    if (isBlacklisted) {
      console.warn(`Blacklisted token used: ${payload.jti}`);
      return res.status(401).json({ error: 'Token has been revoked' });
    }

    req.user = payload;
    req.tokenId = payload.jti;
    next();
  } catch (err) {
    console.error('Token verification failed:', {
      error: err.message,
      ip: req.ip,
      userAgent: req.headers['user-agent']
    });

    if (err.name === 'TokenExpiredError') {
      return res.status(401).json({ error: 'Token expired', code: 'TOKEN_EXPIRED' });
    }
    return res.status(401).json({ error: 'Invalid token' });
  }
}

// Rate limiting for auth endpoints
const authLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,  // 15 minutes
  max: 10,  // 10 attempts per window
  message: { error: 'Too many authentication attempts' },
  standardHeaders: true,
  legacyHeaders: false
});

// Token refresh endpoint with rotation
app.post('/api/auth/refresh', authLimiter, async (req, res) => {
  const { refreshToken } = req.body;

  if (!refreshToken) {
    return res.status(400).json({ error: 'Refresh token required' });
  }

  try {
    const { payload, header } = jwt.verify(
      refreshToken, 
      JWT_CONFIG.publicKey, 
      JWT_CONFIG.verifyOptions
    );

    // Validate it's a refresh token
    if (payload.type !== 'refresh') {
      return res.status(401).json({ error: 'Invalid token type' });
    }

    // Check if refresh token is revoked
    const isRevoked = await redis.get(`revoked:${payload.jti}`);
    if (isRevoked) {
      // Potential token theft - revoke entire family
      await redis.set(`family:revoked:${payload.familyId}`, '1', 'EX', 604800);
      console.error(`Refresh token reuse detected: ${payload.jti}`);
      return res.status(401).json({ error: 'Token has been revoked' });
    }

    // Check if token family is revoked
    const familyRevoked = await redis.get(`family:revoked:${payload.familyId}`);
    if (familyRevoked) {
      return res.status(401).json({ error: 'Session terminated' });
    }

    // Revoke the used refresh token (rotation)
    const ttl = Math.ceil((payload.exp - Date.now() / 1000));
    await redis.set(`revoked:${payload.jti}`, '1', 'EX', Math.max(ttl, 1));

    // Fetch fresh user data
    const user = await getUserById(payload.sub);
    if (!user || !user.active) {
      return res.status(401).json({ error: 'User not found or inactive' });
    }

    // Generate new token pair
    const tokens = generateTokenPair(user);

    // Store new refresh token reference
    await redis.set(
      `refresh:${tokens.jti}`, 
      JSON.stringify({ userId: user.id, familyId: payload.familyId }),
      'EX',
      604800  // 7 days
    );

    // Audit log
    console.info('Token refreshed:', {
      userId: user.id,
      oldJti: payload.jti,
      newJti: tokens.jti,
      ip: req.ip
    });

    res.json({
      accessToken: tokens.accessToken,
      refreshToken: tokens.refreshToken,
      expiresIn: 900  // 15 minutes
    });
  } catch (err) {
    console.error('Refresh token error:', err.message);
    return res.status(401).json({ error: 'Invalid refresh token' });
  }
});

// Logout - revoke tokens
app.post('/api/auth/logout', verifyAccessToken, async (req, res) => {
  try {
    // Blacklist access token until expiry
    const ttl = Math.ceil(req.user.exp - Date.now() / 1000);
    await redis.set(`blacklist:${req.tokenId}`, '1', 'EX', Math.max(ttl, 1));

    // Revoke associated refresh tokens by family
    await redis.set(`family:revoked:${req.tokenId}`, '1', 'EX', 604800);

    console.info('User logged out:', { userId: req.user.sub, ip: req.ip });

    res.json({ message: 'Logged out successfully' });
  } catch (err) {
    console.error('Logout error:', err);
    res.status(500).json({ error: 'Logout failed' });
  }
});

// Protected route example
app.get('/api/profile', verifyAccessToken, (req, res) => {
  res.json({
    id: req.user.sub,
    username: req.user.username,
    role: req.user.role
  });
});

// Mock user lookup
async function getUserById(id) {
  // Replace with actual database lookup
  return { id, username: 'user', role: 'user', active: true };
}

validateKeyConfig();
app.listen(3000);
```

**Defense in Depth Layers**:

1. **Algorithm Enforcement**:
```javascript
// Layer 1: Whitelist in verify options
const verifyOptions = { algorithms: ['RS256'] };

// Layer 2: Additional header check after verification
if (header.alg !== 'RS256') {
  throw new Error('Algorithm mismatch');
}

// Layer 3: Use asymmetric keys - public key cannot sign
// Even if attacker tries HS256 with public key, it fails
```

2. **Token Revocation**:
```javascript
// Per-token blacklist with Redis
await redis.set(`blacklist:${jti}`, '1', 'EX', tokenTTL);

// Family-based revocation for security events
await redis.set(`family:revoked:${familyId}`, '1', 'EX', 604800);

// Refresh token rotation - single use tokens
await redis.set(`revoked:${refreshJti}`, '1', 'EX', ttl);
```

3. **Token Theft Detection**:
```javascript
// Detect refresh token reuse (indicates theft)
const isRevoked = await redis.get(`revoked:${payload.jti}`);
if (isRevoked) {
  // Revoke entire token family
  await redis.set(`family:revoked:${payload.familyId}`, '1');
  alertSecurityTeam(payload);
}
```

**Additional Protections**:
- **Key rotation**: Implement periodic key rotation with `kid` (key ID) header to support multiple valid keys during transition
- **Clock skew tolerance**: Configure `clockTolerance` option for distributed systems but keep it minimal (30-60 seconds)
- **Payload minimization**: Include only necessary claims in access tokens; sensitive data should be fetched from database
- **Secure transmission**: Always use HTTPS; set `Secure` and `HttpOnly` flags if storing refresh tokens in cookies
- **Monitoring and alerting**: Log all authentication failures, track unusual patterns (multiple failed refreshes, geographic anomalies)

JWT implementation requires careful attention to secret management and algorithm selection. Weak secrets are a critical vulnerability that allows attackers to forge valid tokens.

**VULNERABLE CODE**:

```java
import io.jsonwebtoken.Jwts;
import io.jsonwebtoken.SignatureAlgorithm;
import io.jsonwebtoken.Claims;
import javax.servlet.http.*;
import java.util.Date;

public class VulnerableJwtService {
    // VULNERABLE: Weak, hardcoded secret
    private static final String SECRET = "secret123";

    public String generateToken(String username) {
        // VULNERABLE: No expiration, weak algorithm consideration
        return Jwts.builder()
            .setSubject(username)
            .setIssuedAt(new Date())
            .signWith(SignatureAlgorithm.HS256, SECRET)
            .compact();
    }

    public String validateToken(String token) {
        // VULNERABLE: No algorithm verification, trusts header
        Claims claims = Jwts.parser()
            .setSigningKey(SECRET)
            .parseClaimsJws(token)
            .getBody();
        return claims.getSubject();
    }

    public void handleRequest(HttpServletRequest request, HttpServletResponse response) {
        String token = request.getHeader("Authorization");
        // VULNERABLE: No bearer prefix validation
        String username = validateToken(token);
        // Process request for user...
    }
}
```

**Attack Payload**:
```bash
# Brute-force weak secret using hashcat
hashcat -m 16500 jwt_token.txt rockyou.txt

# Once secret "secret123" is cracked, forge admin token:
python3 -c "
import jwt
token = jwt.encode({'sub': 'admin', 'role': 'administrator'}, 'secret123', algorithm='HS256')
print(token)
"
```

**Why This Is Dangerous**:
- Weak secret ("secret123") can be brute-forced in seconds with hashcat or jwt_tool
- Hardcoded secrets get committed to source control and leaked
- No token expiration allows stolen tokens to be used indefinitely
- Missing algorithm enforcement enables algorithm confusion attacks (CVE-2022-23529)
- No issuer/audience validation allows tokens from other applications

**SECURE VERSION**:

```java
import io.jsonwebtoken.Jwts;
import io.jsonwebtoken.SignatureAlgorithm;
import io.jsonwebtoken.Claims;
import io.jsonwebtoken.security.Keys;
import io.jsonwebtoken.JwtException;
import javax.crypto.SecretKey;
import javax.servlet.http.*;
import java.util.Date;
import java.util.Base64;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class SecureJwtService {
    private static final Logger logger = LoggerFactory.getLogger(SecureJwtService.class);

    // SECURE: Strong secret from environment variable (256-bit minimum for HS256)
    private final SecretKey secretKey;
    private static final long TOKEN_VALIDITY_MS = 15 * 60 * 1000; // 15 minutes
    private static final String ISSUER = "myapp.example.com";
    private static final String AUDIENCE = "myapp-api";

    public SecureJwtService() {
        // SECURE: Load secret from environment, minimum 256 bits
        String secret = System.getenv("JWT_SECRET_KEY");
        if (secret == null || secret.length() < 32) {
            throw new IllegalStateException("JWT_SECRET_KEY must be at least 256 bits");
        }
        this.secretKey = Keys.hmacShaKeyFor(Base64.getDecoder().decode(secret));
    }

    public String generateToken(String username, String role) {
        Date now = new Date();
        Date expiry = new Date(now.getTime() + TOKEN_VALIDITY_MS);

        return Jwts.builder()
            .setSubject(username)
            .setIssuer(ISSUER)
            .setAudience(AUDIENCE)
            .setIssuedAt(now)
            .setExpiration(expiry)  // SECURE: Short expiration
            .claim("role", role)
            .signWith(secretKey, SignatureAlgorithm.HS256)  // SECURE: Strong key
            .compact();
    }

    public Claims validateToken(String token) throws JwtException {
        // SECURE: Explicit algorithm, issuer, audience validation
        return Jwts.parserBuilder()
            .setSigningKey(secretKey)
            .requireIssuer(ISSUER)
            .requireAudience(AUDIENCE)
            .build()
            .parseClaimsJws(token)
            .getBody();
    }
}
```

**Key Security Controls**:
- **Strong Secret**: Minimum 256-bit key loaded from environment variable, not hardcoded
- **Short Expiration**: 15-minute token validity limits attack window for stolen tokens
- **Claims Validation**: Issuer and audience claims prevent token reuse across applications
- **Explicit Algorithm**: SignatureAlgorithm explicitly specified prevents algorithm confusion
- **Secure Key Generation**: Using Keys.hmacShaKeyFor() ensures proper key handling

Production JWT implementations need refresh token rotation, token revocation, and comprehensive security monitoring. Here's a complete production pattern:

**PRODUCTION PATTERN**:

```java
import io.jsonwebtoken.*;
import io.jsonwebtoken.security.Keys;
import javax.crypto.SecretKey;
import java.security.SecureRandom;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.time.Instant;
import java.time.temporal.ChronoUnit;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;
import org.springframework.beans.factory.annotation.Value;

@Service
public class ProductionJwtService {
    private static final Logger logger = LoggerFactory.getLogger(ProductionJwtService.class);
    private static final Logger auditLogger = LoggerFactory.getLogger("AUDIT");

    private final SecretKey accessTokenKey;
    private final SecretKey refreshTokenKey;

    // Token configuration
    private static final long ACCESS_TOKEN_VALIDITY_MS = 15 * 60 * 1000;     // 15 minutes
    private static final long REFRESH_TOKEN_VALIDITY_MS = 7 * 24 * 60 * 60 * 1000; // 7 days
    private static final String ISSUER = "auth.mycompany.com";
    private static final String AUDIENCE = "api.mycompany.com";

    // Token revocation store (use Redis in production)
    private final Set<String> revokedTokens = ConcurrentHashMap.newKeySet();
    private final Map<String, String> refreshTokenFamily = new ConcurrentHashMap<>();

    public ProductionJwtService(
            @Value("${jwt.access.secret}") String accessSecret,
            @Value("${jwt.refresh.secret}") String refreshSecret) {
        // Validate key strength
        validateKeyStrength(accessSecret, "access");
        validateKeyStrength(refreshSecret, "refresh");

        this.accessTokenKey = Keys.hmacShaKeyFor(Base64.getDecoder().decode(accessSecret));
        this.refreshTokenKey = Keys.hmacShaKeyFor(Base64.getDecoder().decode(refreshSecret));

        logger.info("JWT service initialized with separate access/refresh keys");
    }

    private void validateKeyStrength(String secret, String type) {
        if (secret == null || Base64.getDecoder().decode(secret).length < 32) {
            throw new IllegalStateException(
                String.format("%s token secret must be at least 256 bits", type));
        }
    }

    public TokenPair generateTokenPair(UserPrincipal user, String clientIp, String userAgent) {
        String tokenId = generateSecureId();
        String familyId = generateSecureId();

        String accessToken = createAccessToken(user, tokenId);
        String refreshToken = createRefreshToken(user, familyId);

        // Store refresh token family for rotation tracking
        refreshTokenFamily.put(familyId, user.getUsername());

        // Audit log token generation
        auditLogger.info("TOKEN_GENERATED user={} tokenId={} family={} ip={} ua={}",
            user.getUsername(), tokenId, familyId, clientIp, sanitize(userAgent));

        return new TokenPair(accessToken, refreshToken, ACCESS_TOKEN_VALIDITY_MS / 1000);
    }

    private String createAccessToken(UserPrincipal user, String tokenId) {
        Instant now = Instant.now();

        return Jwts.builder()
            .setId(tokenId)
            .setSubject(user.getUsername())
            .setIssuer(ISSUER)
            .setAudience(AUDIENCE)
            .setIssuedAt(Date.from(now))
            .setExpiration(Date.from(now.plus(ACCESS_TOKEN_VALIDITY_MS, ChronoUnit.MILLIS)))
            .claim("type", "access")
            .claim("roles", user.getRoles())
            .claim("permissions", user.getPermissions())
            .signWith(accessTokenKey, SignatureAlgorithm.HS512)  // HS512 for production
            .compact();
    }

    private String createRefreshToken(UserPrincipal user, String familyId) {
        Instant now = Instant.now();

        return Jwts.builder()
            .setId(generateSecureId())
            .setSubject(user.getUsername())
            .setIssuer(ISSUER)
            .setIssuedAt(Date.from(now))
            .setExpiration(Date.from(now.plus(REFRESH_TOKEN_VALIDITY_MS, ChronoUnit.MILLIS)))
            .claim("type", "refresh")
            .claim("family", familyId)  // Token family for rotation detection
            .signWith(refreshTokenKey, SignatureAlgorithm.HS512)
            .compact();
    }

    public Claims validateAccessToken(String token) {
        try {
            Claims claims = Jwts.parserBuilder()
                .setSigningKey(accessTokenKey)
                .requireIssuer(ISSUER)
                .requireAudience(AUDIENCE)
                .build()
                .parseClaimsJws(token)
                .getBody();

            // Check revocation
            if (revokedTokens.contains(claims.getId())) {
                logger.warn("Attempted use of revoked token: {}", claims.getId());
                throw new JwtException("Token has been revoked");
            }

            // Verify token type
            if (!"access".equals(claims.get("type"))) {
                throw new JwtException("Invalid token type");
            }

            return claims;

        } catch (ExpiredJwtException e) {
            logger.debug("Access token expired for user: {}", e.getClaims().getSubject());
            throw e;
        } catch (JwtException e) {
            logger.warn("Invalid access token: {}", e.getMessage());
            throw e;
        }
    }

    public TokenPair refreshTokens(String refreshToken, String clientIp) {
        try {
            Claims claims = Jwts.parserBuilder()
                .setSigningKey(refreshTokenKey)
                .requireIssuer(ISSUER)
                .build()
                .parseClaimsJws(refreshToken)
                .getBody();

            // Verify token type
            if (!"refresh".equals(claims.get("type"))) {
                throw new JwtException("Invalid token type for refresh");
            }

            String familyId = claims.get("family", String.class);
            String username = claims.getSubject();

            // CRITICAL: Check for token reuse (replay attack detection)
            if (!refreshTokenFamily.containsKey(familyId)) {
                // Token family was revoked - possible stolen token replay
                auditLogger.error("SECURITY_ALERT refresh_token_replay user={} family={} ip={}",
                    username, familyId, clientIp);

                // Revoke all tokens for this user
                revokeAllUserTokens(username);
                throw new SecurityException("Refresh token reuse detected - all sessions revoked");
            }

            // Rotate: invalidate old family, create new
            refreshTokenFamily.remove(familyId);

            UserPrincipal user = loadUserPrincipal(username);
            TokenPair newTokens = generateTokenPair(user, clientIp, "refresh-rotation");

            auditLogger.info("TOKEN_REFRESHED user={} oldFamily={} ip={}",
                username, familyId, clientIp);

            return newTokens;

        } catch (ExpiredJwtException e) {
            auditLogger.info("REFRESH_TOKEN_EXPIRED user={} ip={}",
                e.getClaims().getSubject(), clientIp);
            throw new JwtException("Refresh token expired - please login again");
        }
    }

    public void revokeToken(String tokenId, String reason, String revokedBy) {
        revokedTokens.add(tokenId);
        auditLogger.info("TOKEN_REVOKED tokenId={} reason={} by={}",
            tokenId, reason, revokedBy);
    }

    public void revokeAllUserTokens(String username) {
        // Remove all refresh token families for user
        refreshTokenFamily.entrySet().removeIf(e -> e.getValue().equals(username));
        auditLogger.warn("ALL_TOKENS_REVOKED user={}", username);
    }

    private String generateSecureId() {
        byte[] bytes = new byte[32];
        new SecureRandom().nextBytes(bytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);
    }

    private String sanitize(String input) {
        if (input == null) return "unknown";
        return input.replaceAll("[^a-zA-Z0-9.\\-/ ]", "").substring(0, Math.min(100, input.length()));
    }

    private UserPrincipal loadUserPrincipal(String username) {
        // Load from database in real implementation
        throw new UnsupportedOperationException("Implement user loading");
    }

    // Token pair response class
    public static class TokenPair {
        public final String accessToken;
        public final String refreshToken;
        public final long expiresIn;

        public TokenPair(String accessToken, String refreshToken, long expiresIn) {
            this.accessToken = accessToken;
            this.refreshToken = refreshToken;
            this.expiresIn = expiresIn;
        }
    }

    public static class UserPrincipal {
        private String username;
