JWT algorithm confusion is one of the most critical authentication vulnerabilities. If your code doesn't explicitly enforce the expected signing algorithm, attackers can forge tokens by manipulating the `alg` header field.

**VULNERABLE CODE**:

```go
package main

import (
	"fmt"
	"net/http"

	"github.com/golang-jwt/jwt/v5"
)

var secretKey = []byte("my-secret-key")

// VULNERABLE: Does not enforce algorithm
func validateTokenUnsafe(tokenString string) (*jwt.Token, error) {
	// This accepts ANY algorithm specified in the token header!
	token, err := jwt.Parse(tokenString, func(token *jwt.Token) (interface{}, error) {
		return secretKey, nil
	})

	if err != nil {
		return nil, err
	}

	return token, nil
}

func protectedHandler(w http.ResponseWriter, r *http.Request) {
	tokenString := r.Header.Get("Authorization")

	token, err := validateTokenUnsafe(tokenString)
	if err != nil || !token.Valid {
		http.Error(w, "Unauthorized", http.StatusUnauthorized)
		return
	}

	claims := token.Claims.(jwt.MapClaims)
	fmt.Fprintf(w, "Welcome, %s!", claims["username"])
}
```

**Attack Payload**:
```text
# Original legitimate token (HS256):
eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJ1c2VybmFtZSI6InVzZXIiLCJyb2xlIjoiYWRtaW4ifQ.signature

# Forged token with alg=none (no signature required!):
eyJhbGciOiJub25lIiwidHlwIjoiSldUIn0.eyJ1c2VybmFtZSI6ImFkbWluIiwicm9sZSI6ImFkbWluIn0.

# Decoded header: {"alg":"none","typ":"JWT"}
# Decoded payload: {"username":"admin","role":"admin"}
# Signature: empty (not required when alg=none)
```

**Why This Is Dangerous**:
- The `jwt.Parse()` function accepts whatever algorithm is specified in the token's header
- Attacker can set `alg: none` to bypass signature verification entirely
- Attacker can switch from RS256 to HS256 and sign with the public key as a secret
- No validation ensures the token was signed by your server

**SECURE VERSION**:

```go
package main

import (
	"errors"
	"fmt"
	"net/http"
	"strings"

	"github.com/golang-jwt/jwt/v5"
)

var secretKey = []byte("my-secret-key-at-least-32-bytes!")

// SECURE: Explicitly enforce HS256 algorithm
func validateTokenSecure(tokenString string) (*jwt.Token, error) {
	token, err := jwt.Parse(tokenString, func(token *jwt.Token) (interface{}, error) {
		// CRITICAL: Verify the signing method is exactly what we expect
		if _, ok := token.Method.(*jwt.SigningMethodHMAC); !ok {
			return nil, fmt.Errorf("unexpected signing method: %v", token.Header["alg"])
		}

		// Additional check: explicitly verify algorithm name
		if token.Method.Alg() != "HS256" {
			return nil, fmt.Errorf("invalid algorithm: %s", token.Method.Alg())
		}

		return secretKey, nil
	})

	if err != nil {
		return nil, err
	}

	if !token.Valid {
		return nil, errors.New("invalid token")
	}

	return token, nil
}

func secureProtectedHandler(w http.ResponseWriter, r *http.Request) {
	authHeader := r.Header.Get("Authorization")
	if !strings.HasPrefix(authHeader, "Bearer ") {
		http.Error(w, "Missing bearer token", http.StatusUnauthorized)
		return
	}

	tokenString := strings.TrimPrefix(authHeader, "Bearer ")

	token, err := validateTokenSecure(tokenString)
	if err != nil {
		// Log the error for monitoring but don't expose details
		fmt.Printf("Token validation failed: %v\n", err)
		http.Error(w, "Unauthorized", http.StatusUnauthorized)
		return
	}

	claims, ok := token.Claims.(jwt.MapClaims)
	if !ok {
		http.Error(w, "Invalid token claims", http.StatusUnauthorized)
		return
	}

	fmt.Fprintf(w, "Welcome, %s!", claims["username"])
}
```

**Key Security Controls**:
- **Algorithm enforcement**: Explicitly check `token.Method` type before returning the key, rejecting any algorithm other than expected
- **Double verification**: Check both the signing method type AND the algorithm name string
- **Bearer token parsing**: Properly extract token from Authorization header with Bearer prefix
- **Error handling**: Fail securely without leaking validation details to attackers

Excellent questions! RSA-based JWTs require additional care to prevent algorithm confusion attacks, and production systems need proper token lifecycle management including refresh and revocation mechanisms.

**PRODUCTION PATTERN**:

```go
package auth

import (
	"context"
	"crypto/rsa"
	"errors"
	"fmt"
	"log/slog"
	"net/http"
	"strings"
	"sync"
	"time"

	"github.com/golang-jwt/jwt/v5"
	"github.com/google/uuid"
	"github.com/redis/go-redis/v9"
)

type JWTService struct {
	privateKey     *rsa.PrivateKey
	publicKey      *rsa.PublicKey
	redis          *redis.Client
	accessTTL      time.Duration
	refreshTTL     time.Duration
	issuer         string
	logger         *slog.Logger
	revokedTokens  sync.Map // In-memory cache for quick lookups
}

type TokenPair struct {
	AccessToken  string `json:"access_token"`
	RefreshToken string `json:"refresh_token"`
	ExpiresIn    int64  `json:"expires_in"`
	TokenType    string `json:"token_type"`
}

type CustomClaims struct {
	jwt.RegisteredClaims
	UserID    string   `json:"user_id"`
	Username  string   `json:"username"`
	Roles     []string `json:"roles"`
	TokenType string   `json:"token_type"` // "access" or "refresh"
}

func NewJWTService(
	privateKey *rsa.PrivateKey,
	publicKey *rsa.PublicKey,
	redisClient *redis.Client,
	logger *slog.Logger,
) *JWTService {
	return &JWTService{
		privateKey: privateKey,
		publicKey:  publicKey,
		redis:      redisClient,
		accessTTL:  15 * time.Minute,  // Short-lived access tokens
		refreshTTL: 7 * 24 * time.Hour, // Longer refresh tokens
		issuer:     "myapp.example.com",
		logger:     logger,
	}
}

// GenerateTokenPair creates both access and refresh tokens
func (s *JWTService) GenerateTokenPair(ctx context.Context, userID, username string, roles []string) (*TokenPair, error) {
	now := time.Now()
	jti := uuid.New().String()

	// Access token - short lived, contains user info
	accessClaims := CustomClaims{
		RegisteredClaims: jwt.RegisteredClaims{
			Issuer:    s.issuer,
			Subject:   userID,
			Audience:  jwt.ClaimStrings{"myapp-api"},
			ExpiresAt: jwt.NewNumericDate(now.Add(s.accessTTL)),
			IssuedAt:  jwt.NewNumericDate(now),
			NotBefore: jwt.NewNumericDate(now),
			ID:        jti,
		},
		UserID:    userID,
		Username:  username,
		Roles:     roles,
		TokenType: "access",
	}

	// SECURE: Always use RS256 with explicit method selection
	accessToken := jwt.NewWithClaims(jwt.SigningMethodRS256, accessClaims)
	accessTokenString, err := accessToken.SignedString(s.privateKey)
	if err != nil {
		s.logger.Error("failed to sign access token", "error", err, "user_id", userID)
		return nil, fmt.Errorf("failed to generate access token: %w", err)
	}

	// Refresh token - longer lived, minimal claims
	refreshJTI := uuid.New().String()
	refreshClaims := CustomClaims{
		RegisteredClaims: jwt.RegisteredClaims{
			Issuer:    s.issuer,
			Subject:   userID,
			ExpiresAt: jwt.NewNumericDate(now.Add(s.refreshTTL)),
			IssuedAt:  jwt.NewNumericDate(now),
			ID:        refreshJTI,
		},
		UserID:    userID,
		TokenType: "refresh",
	}

	refreshToken := jwt.NewWithClaims(jwt.SigningMethodRS256, refreshClaims)
	refreshTokenString, err := refreshToken.SignedString(s.privateKey)
	if err != nil {
		s.logger.Error("failed to sign refresh token", "error", err, "user_id", userID)
		return nil, fmt.Errorf("failed to generate refresh token: %w", err)
	}

	// Store refresh token JTI in Redis for revocation tracking
	err = s.redis.Set(ctx, "refresh:"+refreshJTI, userID, s.refreshTTL).Err()
	if err != nil {
		s.logger.Error("failed to store refresh token", "error", err, "user_id", userID)
		return nil, fmt.Errorf("failed to store refresh token: %w", err)
	}

	s.logger.Info("token pair generated",
		"user_id", userID,
		"access_jti", jti,
		"refresh_jti", refreshJTI,
	)

	return &TokenPair{
		AccessToken:  accessTokenString,
		RefreshToken: refreshTokenString,
		ExpiresIn:    int64(s.accessTTL.Seconds()),
		TokenType:    "Bearer",
	}, nil
}

// ValidateAccessToken validates and returns claims from an access token
func (s *JWTService) ValidateAccessToken(ctx context.Context, tokenString string) (*CustomClaims, error) {
	token, err := jwt.ParseWithClaims(tokenString, &CustomClaims{}, func(token *jwt.Token) (interface{}, error) {
		// CRITICAL: Enforce RS256 algorithm - prevents algorithm confusion attacks
		if _, ok := token.Method.(*jwt.SigningMethodRSA); !ok {
			return nil, fmt.Errorf("unexpected signing method: %v", token.Header["alg"])
		}

		// Double-check algorithm name
		if token.Method.Alg() != "RS256" {
			return nil, fmt.Errorf("invalid algorithm: expected RS256, got %s", token.Method.Alg())
		}

		return s.publicKey, nil
	}, jwt.WithIssuer(s.issuer), jwt.WithValidMethods([]string{"RS256"}))

	if err != nil {
		return nil, fmt.Errorf("token parsing failed: %w", err)
	}

	claims, ok := token.Claims.(*CustomClaims)
	if !ok || !token.Valid {
		return nil, errors.New("invalid token claims")
	}

	// Verify this is an access token, not a refresh token
	if claims.TokenType != "access" {
		return nil, errors.New("invalid token type: expected access token")
	}

	// Check if token has been revoked
	if s.isTokenRevoked(ctx, claims.ID) {
		s.logger.Warn("revoked token used", "jti", claims.ID, "user_id", claims.UserID)
		return nil, errors.New("token has been revoked")
	}

	return claims, nil
}

// RefreshTokens validates refresh token and issues new token pair
func (s *JWTService) RefreshTokens(ctx context.Context, refreshTokenString string) (*TokenPair, error) {
	token, err := jwt.ParseWithClaims(refreshTokenString, &CustomClaims{}, func(token *jwt.Token) (interface{}, error) {
		if _, ok := token.Method.(*jwt.SigningMethodRSA); !ok {
			return nil, fmt.Errorf("unexpected signing method: %v", token.Header["alg"])
		}
		return s.publicKey, nil
	}, jwt.WithIssuer(s.issuer), jwt.WithValidMethods([]string{"RS256"}))

	if err != nil {
		return nil, fmt.Errorf("refresh token invalid: %w", err)
	}

	claims, ok := token.Claims.(*CustomClaims)
	if !ok || !token.Valid {
		return nil, errors.New("invalid refresh token")
	}

	if claims.TokenType != "refresh" {
		return nil, errors.New("invalid token type: expected refresh token")
	}

	// Verify refresh token exists in Redis (not revoked)
	storedUserID, err := s.redis.Get(ctx, "refresh:"+claims.ID).Result()
	if err == redis.Nil {
		s.logger.Warn("refresh token not found or revoked", "jti", claims.ID)
		return nil, errors.New("refresh token revoked or expired")
	}
	if err != nil {
		return nil, fmt.Errorf("failed to verify refresh token: %w", err)
	}

	if storedUserID != claims.UserID {
		s.logger.Error("user ID mismatch in refresh token", "expected", storedUserID, "got", claims.UserID)
		return nil, errors.New("token validation failed")
	}

	// Rotate refresh token: revoke old one
	s.redis.Del(ctx, "refresh:"+claims.ID)

	// Fetch current user roles from database (not shown)
	// This ensures revoked permissions take effect on refresh
	roles := []string{"user"} // Replace with actual role lookup

	s.logger.Info("token refreshed", "user_id", claims.UserID, "old_jti", claims.ID)

	return s.GenerateTokenPair(ctx, claims.UserID, claims.Username, roles)
}

// RevokeAllUserTokens revokes all tokens for a user (logout everywhere)
func (s *JWTService) RevokeAllUserTokens(ctx context.Context, userID string) error {
	// Add user to revocation list with timestamp
	err := s.redis.Set(ctx, "revoked_user:"+userID, time.Now().Unix(), 24*time.Hour).Err()
	if err != nil {
		return fmt.Errorf("failed to revoke user tokens: %w", err)
	}

	// Delete all refresh tokens for user (scan and delete pattern)
	iter := s.redis.Scan(ctx, 0, "refresh:*", 100).Iterator()
	for iter.Next(ctx) {
		key := iter.Val()
		val, _ := s.redis.Get(ctx, key).Result()
		if val == userID {
			s.redis.Del(ctx, key)
		}
	}

	s.logger.Info("all tokens revoked for user", "user_id", userID)
	return nil
}

func (s *JWTService) isTokenRevoked(ctx context.Context, jti string) bool {
	// Check in-memory cache first
	if _, revoked := s.revokedTokens.Load(jti); revoked {
		return true
	}

	// Check Redis for explicit revocation
	exists, _ := s.redis.Exists(ctx, "revoked:"+jti).Result()
	return exists > 0
}

// Middleware for protected routes
func (s *JWTService) AuthMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		authHeader := r.Header.Get("Authorization")
		if !strings.HasPrefix(authHeader, "Bearer ") {
			http.Error(w, "Missing authorization header", http.StatusUnauthorized)
			return
		}

		tokenString := strings.TrimPrefix(authHeader, "Bearer ")
		claims, err := s.ValidateAccessToken(r.Context(), tokenString)
		if err != nil {
			s.logger.Warn("authentication failed",
				"error", err,
				"remote_addr", r.RemoteAddr,
				"path", r.URL.Path,
			)
			http.Error(w, "Unauthorized", http.StatusUnauthorized)
			return
		}

		// Add claims to context for downstream handlers
		ctx := context.WithValue(r.Context(), "claims", claims)
		next.ServeHTTP(w, r.WithContext(ctx))
	})
}
```

**Defense in Depth Layers**:

1. **Algorithm Enforcement at Multiple Levels**:
