**Key Security Controls**:
- **ValidAlgorithms whitelist**: Explicitly specifies which algorithms are allowed, blocking 'none' and unexpected algorithms
- **RequireSignedTokens = true**: Ensures tokens without signatures are rejected
- **Double algorithm verification**: Checks algorithm both during validation and after via the validated token object
- **Issuer/Audience validation**: Prevents tokens from other systems being accepted
- **Security logging**: Critical algorithm attacks are logged for monitoring

The RS256/HS256 confusion attack is particularly dangerous because the public key is often easily accessible. If your validation accepts both algorithms, an attacker can sign a forged token using your public key as an HMAC secret. Here's a production-ready implementation that prevents this:

**PRODUCTION PATTERN**:

```csharp
using System;
using System.Collections.Generic;
using System.IdentityModel.Tokens.Jwt;
using System.Linq;
using System.Security.Claims;
using System.Security.Cryptography;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Caching.Memory;
using Microsoft.Extensions.Logging;
using Microsoft.IdentityModel.Tokens;

namespace SecureApi.Services
{
    public class ProductionJwtService
    {
        private readonly RSA _privateKey;
        private readonly RSA _publicKey;
        private readonly JwtConfiguration _config;
        private readonly ILogger<ProductionJwtService> _logger;
        private readonly IMemoryCache _tokenBlacklist;
        private readonly IHttpContextAccessor _httpContextAccessor;

        // CRITICAL: Only allow asymmetric algorithms when using RSA keys
        private static readonly string[] AsymmetricAlgorithms = new[]
        {
            SecurityAlgorithms.RsaSha256,
            SecurityAlgorithms.RsaSha384,
            SecurityAlgorithms.RsaSha512
        };

        public ProductionJwtService(
            JwtConfiguration config,
            ILogger<ProductionJwtService> logger,
            IMemoryCache tokenBlacklist,
            IHttpContextAccessor httpContextAccessor)
        {
            _config = config ?? throw new ArgumentNullException(nameof(config));
            _logger = logger ?? throw new ArgumentNullException(nameof(logger));
            _tokenBlacklist = tokenBlacklist;
            _httpContextAccessor = httpContextAccessor;

            // Load RSA keys from secure storage
            _privateKey = LoadPrivateKey(config.PrivateKeyPath);
            _publicKey = LoadPublicKey(config.PublicKeyPath);

            ValidateKeyConfiguration();
        }

        private void ValidateKeyConfiguration()
        {
            // Ensure minimum key size for security
            if (_privateKey.KeySize < 2048)
            {
                throw new InvalidOperationException(
                    "RSA key must be at least 2048 bits for production use");
            }
        }

        public TokenValidationResult ValidateToken(string token)
        {
            if (string.IsNullOrWhiteSpace(token))
            {
                return TokenValidationResult.Failed("Empty token");
            }

            // Check token blacklist (for logout/revocation)
            var tokenId = GetTokenId(token);
            if (tokenId != null && _tokenBlacklist.TryGetValue(
                $"revoked:{tokenId}", out _))
            {
                _logger.LogWarning("Revoked token usage attempt: {TokenId}", tokenId);
                return TokenValidationResult.Failed("Token has been revoked");
            }

            var handler = new JwtSecurityTokenHandler();

            // CRITICAL: Use RsaSecurityKey to prevent algorithm confusion
            // RSA keys can ONLY be used with RSA algorithms
            var rsaSecurityKey = new RsaSecurityKey(_publicKey)
            {
                KeyId = _config.KeyId // Key rotation support
            };

            var validationParameters = new TokenValidationParameters
            {
                ValidateIssuerSigningKey = true,
                IssuerSigningKey = rsaSecurityKey,

                // CRITICAL: Only allow RSA algorithms - blocks HS256 attacks
                ValidAlgorithms = AsymmetricAlgorithms,

                ValidateIssuer = true,
                ValidIssuer = _config.Issuer,
                ValidateAudience = true,
                ValidAudiences = _config.ValidAudiences,
                ValidateLifetime = true,
                ClockSkew = TimeSpan.FromSeconds(30),
                RequireExpirationTime = true,
                RequireSignedTokens = true,

                // Additional: Require specific claims
                RequireAudience = true,

                // Custom validation for additional security checks
                LifetimeValidator = ValidateTokenLifetime,
                IssuerSigningKeyResolver = ResolveSigningKey
            };

            try
            {
                var principal = handler.ValidateToken(
                    token, validationParameters, out SecurityToken validatedToken);

                // DEFENSE IN DEPTH: Verify algorithm at runtime
                if (validatedToken is JwtSecurityToken jwtToken)
                {
                    // Block any symmetric algorithm usage
                    if (jwtToken.Header.Alg.StartsWith("HS", 
                        StringComparison.OrdinalIgnoreCase))
                    {
                        LogSecurityIncident("Algorithm confusion attack detected", 
                            jwtToken.Header.Alg);
                        return TokenValidationResult.Failed(
                            "Invalid token algorithm");
                    }

                    // Verify it's exactly what we expect
                    if (!AsymmetricAlgorithms.Contains(jwtToken.Header.Alg))
                    {
                        LogSecurityIncident("Unexpected algorithm", 
                            jwtToken.Header.Alg);
                        return TokenValidationResult.Failed(
                            "Invalid token algorithm");
                    }

                    // Verify key ID matches if present
                    if (!string.IsNullOrEmpty(jwtToken.Header.Kid) &&
                        jwtToken.Header.Kid != _config.KeyId)
                    {
                        _logger.LogWarning(
                            "Token signed with unknown key: {KeyId}",
                            jwtToken.Header.Kid);
                        // May indicate key rotation - check alternative keys
                    }
                }

                LogSuccessfulValidation(principal);
                return TokenValidationResult.Success(principal);
            }
            catch (SecurityTokenInvalidAlgorithmException ex)
            {
                LogSecurityIncident("Algorithm attack blocked", ex.Message);
                return TokenValidationResult.Failed("Token validation failed");
            }
            catch (SecurityTokenExpiredException)
            {
                return TokenValidationResult.Failed("Token expired");
            }
            catch (SecurityTokenInvalidSignatureException)
            {
                LogSecurityIncident("Invalid signature", "Potential forgery attempt");
                return TokenValidationResult.Failed("Token validation failed");
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Unexpected token validation error");
                return TokenValidationResult.Failed("Token validation failed");
            }
        }

        private IEnumerable<SecurityKey> ResolveSigningKey(
            string token,
            SecurityToken securityToken,
            string kid,
            TokenValidationParameters parameters)
        {
            // Support key rotation by checking multiple valid keys
            var keys = new List<SecurityKey>
            {
                new RsaSecurityKey(_publicKey) { KeyId = _config.KeyId }
            };

            // Add previous key if within rotation grace period
            if (_config.PreviousPublicKey != null &&
                DateTime.UtcNow < _config.KeyRotationGracePeriodEnd)
            {
                keys.Add(new RsaSecurityKey(_config.PreviousPublicKey)
                {
                    KeyId = _config.PreviousKeyId
                });
            }

            return keys;
        }

        private bool ValidateTokenLifetime(
            DateTime? notBefore,
            DateTime? expires,
            SecurityToken token,
            TokenValidationParameters parameters)
        {
            var now = DateTime.UtcNow;

            if (!expires.HasValue)
                return false;

            // Token must not be valid for more than configured maximum
            if (notBefore.HasValue)
            {
                var tokenLifetime = expires.Value - notBefore.Value;
                if (tokenLifetime > _config.MaxTokenLifetime)
                {
                    _logger.LogWarning(
                        "Token with excessive lifetime detected: {Lifetime}",
                        tokenLifetime);
                    return false;
                }
            }

            return expires > now && (!notBefore.HasValue || notBefore <= now);
        }

        public void RevokeToken(string token)
        {
            var tokenId = GetTokenId(token);
            if (tokenId != null)
            {
                var expiry = GetTokenExpiry(token);
                _tokenBlacklist.Set(
                    $"revoked:{tokenId}",
                    true,
                    expiry ?? DateTime.UtcNow.AddHours(24));

                _logger.LogInformation("Token revoked: {TokenId}", tokenId);
            }
        }

        private void LogSecurityIncident(string incidentType, string details)
        {
            var context = _httpContextAccessor.HttpContext;
            var clientIp = context?.Connection?.RemoteIpAddress?.ToString();
            var userAgent = context?.Request?.Headers["User-Agent"].ToString();

            _logger.LogCritical(
                "SECURITY INCIDENT - {IncidentType}: {Details} | IP: {IP} | UA: {UserAgent}",
                incidentType, details, clientIp, userAgent);

            // Trigger alerting system
            // AlertingService.RaiseSecurityAlert(incidentType, details, clientIp);
        }

        private void LogSuccessfulValidation(ClaimsPrincipal principal)
        {
            var userId = principal.FindFirst(ClaimTypes.NameIdentifier)?.Value;
            _logger.LogDebug("Token validated for user: {UserId}", userId);
        }

        private string GetTokenId(string token)
        {
            try
            {
                var handler = new JwtSecurityTokenHandler();
                var jwt = handler.ReadJwtToken(token);
                return jwt.Id;
            }
            catch
            {
                return null;
            }
        }

        private DateTime? GetTokenExpiry(string token)
        {
            try
            {
                var handler = new JwtSecurityTokenHandler();
                var jwt = handler.ReadJwtToken(token);
                return jwt.ValidTo;
            }
            catch
            {
                return null;
            }
        }

        private RSA LoadPrivateKey(string path)
        {
            // In production, load from HSM, Azure Key Vault, AWS KMS, etc.
            var rsa = RSA.Create();
            rsa.ImportFromPem(System.IO.File.ReadAllText(path));
            return rsa;
        }

        private RSA LoadPublicKey(string path)
        {
            var rsa = RSA.Create();
            rsa.ImportFromPem(System.IO.File.ReadAllText(path));
            return rsa;
        }
    }

    public class JwtConfiguration
    {
        public string PrivateKeyPath { get; set; }
        public string PublicKeyPath { get; set; }
        public string KeyId { get; set; }
        public string Issuer { get; set; }
        public string[] ValidAudiences { get; set; }
        public TimeSpan MaxTokenLifetime { get; set; } = TimeSpan.FromHours(8);
        public RSA PreviousPublicKey { get; set; }
        public string PreviousKeyId { get; set; }
        public DateTime KeyRotationGracePeriodEnd { get; set; }
    }

    public class TokenValidationResult
    {
        public bool IsValid { get; private set; }
        public ClaimsPrincipal Principal { get; private set; }
        public string Error { get; private set; }

        public static TokenValidationResult Success(ClaimsPrincipal principal)
            => new TokenValidationResult { IsValid = true, Principal = principal };

        public static TokenValidationResult Failed(string error)
            => new TokenValidationResult { IsValid = false, Error = error };
    }
}
